  ('optician-moex-02471', 'optician', 'optician-moex-106-5e38135e', 'sub-optician-01', NULL, 'single_choice', '根據驗光人員法施行細則，下列何者有誤？', '["六歲以上十五歲以下需驗光者，驗光人員可逕為驗光", "所謂一般隱形眼鏡，指非用於治療或診斷之隱形眼鏡", "所稱低視力輔助器具，指以驗光輔助視覺功能之各式光學器具", "設立驗光所，須向所在地縣（市）主管機關申請核准登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "3f68ea157a80", "answer_pdf_sha1": "2ef12f16b137", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
